import React, { Fragment, useEffect, useContext, useState } from "react";
//import React ,{Fragment,useEffect,useContext,useState} from "react";
import { useHistory } from "react-router-dom";
import { LayoutContext } from "../layout";
import { subTotal, quantity, totalCost } from "../partials/Mixins";

import { cartListProduct} from "../partials/FetchApi";
import {getSingleUser} from "../order/FetchApi"
//import { getBrainTreeToken, getPaymentProcess } from "./FetchApi";
//import { fetchData, fetchbrainTree, pay } from "./Action";

//import DropIn from "braintree-web-drop-in-react";
import { fetchData } from "./Action";

const apiURL = process.env.REACT_APP_API_URL;

export const CheckoutComponent = (props) => {
  const history = useHistory();
  const { data, dispatch } = useContext(LayoutContext);

  const [state, setState] = useState({
    address: "",
    phone: "",
    error: false,
    //success: false,
    //clientToken: null,
    //instance: {},
  });

  useEffect(() => {
  fetchData(cartListProduct, dispatch);

  const fetchUserDetails = async () => {
    try {
      const userId = JSON.parse(localStorage.getItem("jwt")).user._id;

      let response = await getSingleUser(userId);

      if (response && response.User) {
        setState((prev) => ({
          ...prev,
          address: response.User.address || "",
          phone: response.User.phone || "",
        }));
      }
    } catch (error) {
      console.log(error);
    }
  };

  fetchUserDetails();

  // eslint-disable-next-line react-hooks/exhaustive-deps
}, []);

  if (data.loading) {
    return (
      <div className="flex items-center justify-center h-screen">
        <svg
          className="w-12 h-12 animate-spin text-gray-600"
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
          xmlns="http://www.w3.org/2000/svg"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth="2"
            d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"
          ></path>
        </svg>
        Please wait until finish
      </div>
    );
  }
  return (
    <Fragment>
      <section className="mx-4 mt-20 md:mx-12 md:mt-32 lg:mt-24">
        <div className="text-2xl mx-2">Organs</div>
        {/* Product List */}
        <div className="flex flex-col md:flex md:space-x-2 md:flex-row">
          <div className="md:w-1/2">
            <CheckoutProducts products={data.cartProduct} />
          </div>
          <div className="w-full order-first md:order-last md:w-1/2">
           


<Fragment>
  <div
    onBlur={(e) => setState({ ...state, error: false })}
    className="p-4 md:p-8"
  >
    {state.error ? (
      <div className="bg-red-200 py-2 px-4 rounded">
        {state.error}
      </div>
    ) : (
      ""
    )}

    <div className="flex flex-col py-2">
      <label className="pb-2">Hospital Address for Delivery</label>
      <input
        value={state.address}
        onChange={(e) =>
          setState({
            ...state,
            address: e.target.value,
            error: false,
          })
        }
        type="text"
        className="border px-4 py-2"
        placeholder="Address..."
      />
    </div>

    <div className="flex flex-col py-2 mb-2">
      <label className="pb-2">Phone</label>
      <input
        value={state.phone}
        onChange={(e) =>
          setState({
            ...state,
            phone: e.target.value,
            error: false,
          })
        }
        type="number"
        className="border px-4 py-2"
        placeholder="+91"
      />
    </div>

    <div


onClick={async () => {
  if (!state.address) {
    return setState({ ...state, error: "Please provide address" });
  }

  if (!state.phone) {
    return setState({ ...state, error: "Please provide phone" });
  }

  let orderData = {
    allProduct: JSON.parse(localStorage.getItem("cart")),
    user: JSON.parse(localStorage.getItem("jwt")).user._id,
    amount: totalCost(),
    address: state.address,
    phone: state.phone,
  };

  console.log("Sending Order:", orderData);

  try {
    let response = await fetch(
      `${apiURL}/api/order/create-order`,
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(orderData),
      }
    );

    let data = await response.json();

    console.log("Server Response:", data);

    if (data && data.success) {
      alert("Order Created Successfully ✅");
//alert("Your Request in process. Please wait till the Procurement centre approves.")
      localStorage.setItem("cart", JSON.stringify([]));
      history.push("/");
    } else {
      alert("Order Failed ❌");
    }
  } catch (err) {
    console.log("Error:", err);
  }
}}


/*


      onClick={async () => {
        if (!state.address) {
          return setState({ ...state, error: "Please provide address" });
        }

        if (!state.phone) {
          return setState({ ...state, error: "Please provide phone" });
        }

        let orderData = {
          allProduct: JSON.parse(localStorage.getItem("cart")),
          user: JSON.parse(localStorage.getItem("jwt")).user._id,
          amount: totalCost(),
          address: state.address,
          phone: state.phone,
        };

        try {
          let response = await fetch(
            `${apiURL}/api/order/create-order`,
            {
              method: "POST",
              headers: {
                "Content-Type": "application/json",
              },
              body: JSON.stringify(orderData),
            }
          );

          let data = await response.json();

          if (data.success) {
            localStorage.setItem("cart", JSON.stringify([]));
            history.push("/");
          }
        } catch (err) {
          console.log(err);
        }
      }}
        */
      className="w-full px-4 py-2 text-center text-white font-semibold cursor-pointer"
      style={{ background: "#303031" }}
    >
      Request now
    </div>
  </div>
</Fragment>


          </div>
        </div>
      </section>
    </Fragment>
  );
};

const CheckoutProducts = ({ products }) => {
  const history = useHistory();

  return (
    <Fragment>
      <div className="grid grid-cols-2 md:grid-cols-1">
        {products !== null && products.length > 0 ? (
          products.map((product, index) => {
            return (
              <div
                key={index}
                className="col-span-1 m-2 md:py-6 md:border-t md:border-b md:my-2 md:mx-0 md:flex md:items-center md:justify-between"
              >
                <div className="md:flex md:items-center md:space-x-4">
                  <img
                    onClick={(e) => history.push(`/products/${product._id}`)}
                    className="cursor-pointer md:h-20 md:w-20 object-cover object-center"
                    src={`${apiURL}/uploads/products/${product.pImages[0]}`}
                    alt="wishListproduct"
                  />
                  <div className="text-lg md:ml-6 truncate">
                    {product.pDescription}
                  </div>
                  {/* <div className="md:ml-6 font-semibold text-gray-600 text-sm">
                    PIN Code: {product.pPrice}{" "}
                  </div> */}
                  <div className="md:ml-6 font-semibold text-gray-600 text-sm">
                    Units : {quantity(product._id)}
                  </div>
                  <div className="font-semibold text-gray-600 text-sm">
                  PIN Code: {subTotal(product._id, product.pincode)}
                  </div>
                </div>
              </div>
            );
          })
        ) : (
          <div>No Request found</div>
        )}
      </div>
    </Fragment>
  );
};

export default CheckoutProducts;
